mapper.select:
select

from TBL_USER_OPT_LOG lg
where 1=1


    and lg.OPER_USER_NAME like '%${logReqParam.operUserName}%'


    and lg.org = #{logReqParam.org}


    and OPER_TYPE = #{logReqParam.operType}


    and OPER_DESC like '%${logReqParam.operDesc}%'


    and OPER_CREATE_TIME >= #{logReqParam.beginDate}


    and OPER_CREATE_TIME <= #{logReqParam.endDate}
